{
  "name": "Gestão de SST - Cursos e Treinamentos",
  "description": "Sistema completo para gestão de treinamentos de Segurança do Trabalho baseado em Normas Regulamentadoras (NRs), com dashboard analítico e controle de validades."
}

export type TrainingStatus = 'VALID' | 'EXPIRING' | 'EXPIRED' | 'NOT_TRAINED';

export interface NRCourse {
  id: string;
  name: string;
  validityYears: number | null; // null means "sem validade" (NR06)
}

export interface TrainingRecord {
  courseId: string;
  completionDate?: string; // ISO format YYYY-MM-DD
  expiryDate?: string;
  status: TrainingStatus;
}

export interface Employee {
  id: string;
  name: string;
  registration: string;
  role: string;
  department: string;
  trainings: Record<string, TrainingRecord>; // Key is courseId
}

export interface DashboardStats {
  totalTrained: number;
  totalExpiring: number;
  totalExpired: number;
  totalNotTrained: number;
}

import { TrainingStatus, TrainingRecord, Employee } from '../types';
import { NR_COURSES } from '../constants';

export const calculateTrainingStatus = (completionDate: string | undefined, validityYears: number | null): TrainingStatus => {
  if (!completionDate) return 'NOT_TRAINED';
  if (validityYears === null) return 'VALID';

  const today = new Date();
  const compDate = new Date(completionDate);
  const expiryDate = new Date(compDate);
  expiryDate.setFullYear(expiryDate.getFullYear() + validityYears);

  const diffTime = expiryDate.getTime() - today.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  if (diffDays < 0) return 'EXPIRED';
  if (diffDays <= 60) return 'EXPIRING';
  return 'VALID';
};

export const getExpiryDate = (completionDate: string | undefined, validityYears: number | null): string | undefined => {
  if (!completionDate || validityYears === null) return undefined;
  const date = new Date(completionDate);
  date.setFullYear(date.getFullYear() + validityYears);
  return date.toISOString().split('T')[0];
};

export const formatEmployeeData = (rawData: any[]): Employee[] => {
  return rawData.map((row, idx) => {
    const trainings: Record<string, TrainingRecord> = {};

    NR_COURSES.forEach(course => {
      const completionDate = row[course.id] || row[course.name];
      const status = calculateTrainingStatus(completionDate, course.validityYears);
      const expiryDate = getExpiryDate(completionDate, course.validityYears);

      trainings[course.id] = {
        courseId: course.id,
        completionDate: completionDate || undefined,
        expiryDate,
        status,
      };
    });

    return {
      id: row.id || `emp-${idx}`,
      name: row.Nome || row.name || 'Sem Nome',
      registration: row.Matrícula || row.registration || '-',
      role: row.Função || row.role || '-',
      department: row.Setor || row.department || '-',
      trainings,
    };
  });
};

