import React from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { Employee, DashboardStats } from '../types';
import { STATUS_CONFIG } from '../constants';

interface DashboardProps {
  employees: Employee[];
}

const Dashboard: React.FC<DashboardProps> = ({ employees }) => {
  const stats: DashboardStats = {
    totalTrained: 0,
    totalExpiring: 0,
    totalExpired: 0,
    totalNotTrained: 0,
  };

  const departmentData: Record<string, DashboardStats> = {};

  employees.forEach(emp => {
    if (!departmentData[emp.department]) {
      departmentData[emp.department] = { totalTrained: 0, totalExpiring: 0, totalExpired: 0, totalNotTrained: 0 };
    }

    Object.values(emp.trainings).forEach(t => {
      if (t.status === 'VALID') {
        stats.totalTrained++;
        departmentData[emp.department].totalTrained++;
      } else if (t.status === 'EXPIRING') {
        stats.totalExpiring++;
        departmentData[emp.department].totalExpiring++;
      } else if (t.status === 'EXPIRED') {
        stats.totalExpired++;
        departmentData[emp.department].totalExpired++;
      } else {
        stats.totalNotTrained++;
        departmentData[emp.department].totalNotTrained++;
      }
    });
  });

  const chartData = Object.entries(departmentData).map(([dept, dStats]) => ({
    name: dept,
    Válidos: dStats.totalTrained,
    Vencendo: dStats.totalExpiring,
    Vencidos: dStats.totalExpired,
    Inexistentes: dStats.totalNotTrained,
  }));

  const pieData = [
    { name: 'Válidos', value: stats.totalTrained, color: '#10b981' },
    { name: 'Vencendo', value: stats.totalExpiring, color: '#f59e0b' },
    { name: 'Vencidos', value: stats.totalExpired, color: '#ef4444' },
    { name: 'Não Capacitados', value: stats.totalNotTrained, color: '#9ca3af' },
  ];

  return (
    <div className="space-y-8 animate-fadeIn">
      <header>
        <h2 className="text-3xl font-bold text-gray-800">Painel de Controle</h2>
        <p className="text-gray-500">Visão geral do status de conformidade das NRs</p>
      </header>

      {/* Metric Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {[
          { label: 'Capacitados', val: stats.totalTrained, icon: '✅', color: 'border-green-500', text: 'text-green-600' },
          { label: 'Próximos do Vencimento', val: stats.totalExpiring, icon: '⚠️', color: 'border-yellow-500', text: 'text-yellow-600' },
          { label: 'Cursos Vencidos', val: stats.totalExpired, icon: '❌', color: 'border-red-500', text: 'text-red-600' },
          { label: 'Não Capacitados', val: stats.totalNotTrained, icon: '⚪', color: 'border-gray-400', text: 'text-gray-600' },
        ].map((m, i) => (
          <div key={i} className={`bg-white p-6 rounded-xl shadow-sm border-l-4 ${m.color} hover:shadow-md transition-shadow`}>
            <div className="flex justify-between items-start">
              <div>
                <p className="text-sm font-medium text-gray-500 uppercase">{m.label}</p>
                <h3 className={`text-2xl font-bold ${m.text}`}>{m.val}</h3>
              </div>
              <span className="text-2xl">{m.icon}</span>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Department Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm">
          <h3 className="text-lg font-semibold mb-6">Status por Departamento</h3>
          <div className="h-80">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} />
                <XAxis dataKey="name" />
                <YAxis />
                <Tooltip />
                <Bar dataKey="Válidos" fill="#10b981" />
                <Bar dataKey="Vencendo" fill="#f59e0b" />
                <Bar dataKey="Vencidos" fill="#ef4444" />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Distribution Pie */}
        <div className="bg-white p-6 rounded-xl shadow-sm flex flex-col">
          <h3 className="text-lg font-semibold mb-6">Distribuição Geral</h3>
          <div className="h-64 flex-1">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={pieData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {pieData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-2 text-xs">
            {pieData.map(d => (
              <div key={d.name} className="flex items-center gap-2">
                <span className="w-3 h-3 rounded-full" style={{ backgroundColor: d.color }}></span>
                <span>{d.name}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Alerts Table */}
      <div className="bg-white rounded-xl shadow-sm overflow-hidden border border-gray-100">
        <div className="p-6 bg-red-50 border-b border-red-100 flex justify-between items-center">
          <h3 className="text-lg font-bold text-red-800 flex items-center gap-2">
            🔔 Alertas de Próximos Vencimentos
          </h3>
          <span className="px-3 py-1 bg-red-100 text-red-700 text-xs font-bold rounded-full">PRIORIDADE</span>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead className="bg-gray-50 text-xs text-gray-500 uppercase tracking-wider">
              <tr>
                <th className="px-6 py-3">Funcionário</th>
                <th className="px-6 py-3">Setor</th>
                <th className="px-6 py-3">Curso</th>
                <th className="px-6 py-3">Vencimento</th>
                <th className="px-6 py-3">Status</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {employees.flatMap(emp => 
                Object.entries(emp.trainings)
                  .filter(([_, t]) => t.status === 'EXPIRING' || t.status === 'EXPIRED')
                  .map(([cid, t], idx) => (
                    <tr key={`${emp.id}-${cid}-${idx}`} className="hover:bg-gray-50 transition-colors">
                      <td className="px-6 py-4 font-medium">{emp.name}</td>
                      <td className="px-6 py-4 text-sm text-gray-500">{emp.department}</td>
                      <td className="px-6 py-4 text-sm font-semibold">{cid}</td>
                      <td className="px-6 py-4 text-sm">{t.expiryDate || 'N/A'}</td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${t.status === 'EXPIRED' ? 'bg-red-100 text-red-700' : 'bg-yellow-100 text-yellow-700'}`}>
                          {t.status === 'EXPIRED' ? 'Vencido' : 'Em 60 dias'}
                        </span>
                      </td>
                    </tr>
                  ))
              ).slice(0, 10)}
            </tbody>
          </table>
          {employees.length === 0 && <div className="p-10 text-center text-gray-400">Nenhum dado disponível. Importe uma planilha.</div>}
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { Employee } from '../types';
