export default EmployeeView;

import React, { useState, useMemo } from 'react';
import { Employee, TrainingStatus } from '../types';
import { NR_COURSES, STATUS_CONFIG } from '../constants';

interface ReportsProps {
  employees: Employee[];
}

const Reports: React.FC<ReportsProps> = ({ employees }) => {
  const [filters, setFilters] = useState({
    department: '',
    status: '' as TrainingStatus | '',
    course: '',
    search: '',
  });

  const departments = useMemo(() => Array.from(new Set(employees.map(e => e.department))), [employees]);

  const reportData = useMemo(() => {
    let result: any[] = [];

    employees.forEach(emp => {
      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const course = NR_COURSES.find(c => c.id === cid);

        const matchesSearch = emp.name.toLowerCase().includes(filters.search.toLowerCase()) || 
                             emp.registration.includes(filters.search);
        const matchesDept = !filters.department || emp.department === filters.department;
        const matchesStatus = !filters.status || t.status === filters.status;
        const matchesCourse = !filters.course || cid === filters.course;

        if (matchesSearch && matchesDept && matchesStatus && matchesCourse) {
          result.push({
            employee: emp,
            courseName: course?.name,
            courseId: cid,
            record: t
          });
        }
      });
    });

    return result;
  }, [employees, filters]);

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center no-print">
        <h2 className="text-2xl font-bold">Relatórios e Consultas</h2>
        <button 
          onClick={handlePrint}
          className="bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition flex items-center gap-2 shadow-sm"
        >
          🖨️ Exportar / Imprimir
        </button>
      </div>

      <div className="bg-white p-6 rounded-xl shadow-sm border border-gray-100 no-print">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Setor</label>
            <select 
              className="w-full border rounded p-2 outline-none focus:ring-2 focus:ring-green-500"
              value={filters.department}
              onChange={(e) => setFilters(f => ({ ...f, department: e.target.value }))}
            >
              <option value="">Todos os Setores</option>
              {departments.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Situação</label>
            <select 
              className="w-full border rounded p-2 outline-none focus:ring-2 focus:ring-green-500"
              value={filters.status}
              onChange={(e) => setFilters(f => ({ ...f, status: e.target.value as any }))}
            >
              <option value="">Todos os Status</option>
              {Object.entries(STATUS_CONFIG).map(([k, v]) => (
                <option key={k} value={k}>{v.label}</option>
              ))}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Curso</label>
            <select 
              className="w-full border rounded p-2 outline-none focus:ring-2 focus:ring-green-500"
              value={filters.course}
              onChange={(e) => setFilters(f => ({ ...f, course: e.target.value }))}
            >
              <option value="">Todos os Cursos</option>
              {NR_COURSES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Busca Rápida</label>
            <input 
              type="text" 
              className="w-full border rounded p-2 outline-none focus:ring-2 focus:ring-green-500"
              placeholder="Nome ou matrícula..."
              value={filters.search}
              onChange={(e) => setFilters(f => ({ ...f, search: e.target.value }))}
            />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm overflow-hidden border">
        <div className="hidden print-only p-8 text-center border-b">
          <h1 className="text-2xl font-bold text-green-800">Relatório de Treinamentos NR - SST</h1>
          <p className="text-gray-500">Emitido em: {new Date().toLocaleDateString('pt-BR')}</p>
        </div>

        <table className="w-full text-left text-sm">
          <thead className="bg-gray-100 text-gray-600 font-bold uppercase text-[10px] tracking-widest border-b">
            <tr>
              <th className="px-6 py-4">Colaborador</th>
              <th className="px-6 py-4">Setor</th>
              <th className="px-6 py-4">Curso</th>
              <th className="px-6 py-4">Data Realização</th>
              <th className="px-6 py-4">Data Vencimento</th>
              <th className="px-6 py-4">Situação</th>
            </tr>
          </thead>
          <tbody className="divide-y">
            {reportData.map((item, idx) => (
              <tr key={idx} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 font-medium">{item.employee.name}</td>
                <td className="px-6 py-4 text-gray-500">{item.employee.department}</td>
                <td className="px-6 py-4 font-semibold">{item.courseName}</td>
                <td className="px-6 py-4">{item.record.completionDate || '---'}</td>
                <td className="px-6 py-4">{item.record.expiryDate || '---'}</td>
                <td className="px-6 py-4">
                  <span className={`px-2 py-1 rounded-full text-[10px] font-bold ${STATUS_CONFIG[item.record.status as TrainingStatus].bg} ${STATUS_CONFIG[item.record.status as TrainingStatus].text}`}>
                    {STATUS_CONFIG[item.record.status as TrainingStatus].label}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {reportData.length === 0 && (
          <div className="p-20 text-center text-gray-400">Nenhum registro encontrado para os filtros aplicados.</div>
        )}
      </div>
    </div>
  );
};

export default Reports;

import React, { useState } from 'react';
import { formatEmployeeData } from '../utils/calculations';
import { Employee } from '../types';

interface ImportDataProps {
  onImport: (data: Employee[]) => void;
}

const ImportData: React.FC<ImportDataProps> = ({ onImport }) => {
  const [csvText, setCsvText] = useState('');
  const [error, setError] = useState('');

  const handleImport = () => {
    try {
      const lines = csvText.trim().split('\n');
      if (lines.length < 2) {
        setError('O formato do CSV parece inválido. Precisa de cabeçalho e pelo menos uma linha.');
        return;
      }

      const headers = lines[0].split(',').map(h => h.trim());
      const rawData = lines.slice(1).map(line => {
        const values = line.split(',').map(v => v.trim());
        const obj: any = {};
        headers.forEach((h, i) => {
          obj[h] = values[i] === '' ? undefined : values[i];
        });
        return obj;
      });

      const employees = formatEmployeeData(rawData);
      onImport(employees);
      setCsvText('');
      setError('');
      alert('Dados importados com sucesso!');
    } catch (err) {
      setError('Erro ao processar os dados. Verifique o formato CSV.');
    }
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <header>
        <h2 className="text-2xl font-bold">Importar Dados</h2>
        <p className="text-gray-500">Cole os dados da sua planilha aqui no formato CSV (separado por vírgulas)</p>
      </header>

