import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import { Employee } from './types';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);

  // Local storage persistence
  useEffect(() => {
    const saved = localStorage.getItem('sst_data');
    if (saved) {
      try {
        setEmployees(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load local data", e);
      }
    }
  }, []);

  const handleImport = (data: Employee[]) => {
    const updated = [...employees, ...data];
    setEmployees(updated);
    localStorage.setItem('sst_data', JSON.stringify(updated));
    setActiveTab('dashboard');
  };

  const renderContent = () => {
    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return <ImportData onImport={handleImport} />;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

