import { TrainingStatus, TrainingRecord, Employee } from '../types';
import { NR_COURSES } from '../constants';

export const getDaysRemaining = (expiryDate: string | undefined): number | null => {
  if (!expiryDate) return null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const expiry = new Date(expiryDate);
  expiry.setHours(0, 0, 0, 0);

  const diffTime = expiry.getTime() - today.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const calculateTrainingStatus = (completionDate: string | undefined, validityYears: number | null): TrainingStatus => {
  if (!completionDate) return 'NOT_TRAINED';
  if (validityYears === null) return 'VALID';

  const daysRemaining = getDaysRemaining(getExpiryDate(completionDate, validityYears));

  if (daysRemaining === null) return 'VALID';
  if (daysRemaining < 0) return 'EXPIRED';
  if (daysRemaining <= 60) return 'EXPIRING';
  return 'VALID';
};

export const getExpiryDate = (completionDate: string | undefined, validityYears: number | null): string | undefined => {
  if (!completionDate || validityYears === null) return undefined;
  const date = new Date(completionDate);
  // Garante que a data não sofra deslocamento de fuso horário ao adicionar anos
  date.setFullYear(date.getFullYear() + validityYears);
  return date.toISOString().split('T')[0];
};

export const formatEmployeeData = (rawData: any[]): Employee[] => {
  return rawData.map((row, idx) => {
    const trainings: Record<string, TrainingRecord> = {};

    NR_COURSES.forEach(course => {
      const completionDate = row[course.id] || row[course.name];
      const expiryDate = getExpiryDate(completionDate, course.validityYears);
      const status = calculateTrainingStatus(completionDate, course.validityYears);

      trainings[course.id] = {
        courseId: course.id,
        completionDate: completionDate || undefined,
        expiryDate,
        status,
      };
    });

    return {
      id: row.id || `emp-${idx}-${Date.now()}`,
      name: row.Nome || row.name || 'Sem Nome',
      registration: row.Matrícula || row.registration || '-',
      role: row.Função || row.role || '-',
      department: row.Setor || row.department || '-',
      trainings,
    };
  });
};

