interface ImportDataProps {
  onImport: (data: Employee[]) => void;
}

const ImportData: React.FC<ImportDataProps> = ({ onImport }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState('');

  const handleImport = () => {
    try {
      if (!inputText.trim()) {
        setError('Por favor, cole os dados da planilha.');
        return;
      }

      const lines = inputText.trim().split(/\r?\n/);
      if (lines.length < 2) {
        setError('O formato parece inválido. Certifique-se de incluir o cabeçalho e os dados.');
        return;
      }

      // Detecta se o separador é TAB (Excel) ou Ponto e Vírgula / Vírgula
      const firstLine = lines[0];
      let separator = '\t';
      if (firstLine.includes(';')) separator = ';';
      else if (firstLine.includes(',') && !firstLine.includes('\t')) separator = ',';

      const headers = lines[0].split(separator).map(h => h.trim());

      const rawData = lines.slice(1).map(line => {
        const values = line.split(separator).map(v => v.trim());
        const obj: any = {};
        headers.forEach((h, i) => {
          // Trata células vazias ou com traços como undefined
          const val = values[i];
          obj[h] = (val === '' || val === '-') ? undefined : val;
        });
        return obj;
      });

      const employees = formatEmployeeData(rawData);
      onImport(employees);
      setInputText('');
      setError('');
      alert(`${employees.length} colaboradores processados com sucesso!`);
    } catch (err) {
      console.error(err);
      setError('Erro ao processar os dados. Verifique se as colunas estão alinhadas corretamente.');
    }
  };

  return (
    <div className="max-w-5xl mx-auto space-y-8 animate-fadeIn">
