          </div>
        )}

        <div className="flex justify-between items-center pt-4">
          <p className="text-xs text-gray-400 font-medium italic">
            O sistema reconhece automaticamente os separadores de coluna da sua planilha.
          </p>
          <div className="flex gap-4">
            <button 
              onClick={() => setInputText('')}
              className="px-8 py-3 text-gray-500 font-bold hover:text-gray-700 transition-colors"
            >
              Limpar Tudo
            </button>
            <button 
              onClick={handleImport}
              className="px-10 py-4 bg-green-600 text-white rounded-2xl hover:bg-green-700 shadow-xl shadow-green-900/20 font-black tracking-wide transition-all hover:scale-105 active:scale-95"
            >
              IMPORTAR AGORA
            </button>
          </div>
        </div>
      </div>

      <section className="bg-gray-100/50 p-8 rounded-3xl border-2 border-dashed border-gray-200">
