interface ImportDataProps {
  onImport: (data: Employee[]) => void;
}

const ImportData: React.FC<ImportDataProps> = ({ onImport }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState('');

  const handleImport = () => {
    try {
      if (!inputText.trim()) {
        setError('Por favor, cole os dados da sua planilha no campo abaixo.');
        return;
      }

      // Divide o texto colado em linhas, lidando com diferentes quebras de linha
      const lines = inputText.trim().split(/\r?\n/);
      if (lines.length < 2) {
        setError('O conteúdo colado parece insuficiente. Certifique-se de incluir o cabeçalho e pelo menos uma linha de dados.');
        return;
      }

      /**
       * Lógica de Detecção de Separador:
       * Ao copiar do Excel/Google Sheets, o separador padrão é o TAB (\t).
       * Também verificamos ponto-e-vírgula ou vírgula caso o usuário cole de um CSV.
       */
      const firstLine = lines[0];
      let separator = '\t'; // Padrão para cópia de planilhas (Excel/Sheets)

      if (!firstLine.includes('\t')) {
        if (firstLine.includes(';')) separator = ';';
        else if (firstLine.includes(',')) separator = ',';
      }

      const headers = lines[0].split(separator).map(h => h.trim());

      const rawData = lines.slice(1).map(line => {
        const values = line.split(separator).map(v => v.trim());
        const obj: any = {};
        headers.forEach((h, i) => {
          const val = values[i];
          // Trata células vazias, hifens ou "N/A" como não realizado (undefined)
          obj[h] = (val === '' || val === '-' || val?.toUpperCase() === 'N/A') ? undefined : val;
        });
        return obj;
      });

      const employees = formatEmployeeData(rawData);

      if (employees.length === 0) {
        setError('Não foi possível identificar dados válidos no conteúdo colado.');
        return;
      }

      onImport(employees);
      setInputText('');
      setError('');
      alert(`Sucesso! ${employees.length} registros foram processados e adicionados ao sistema.`);
    } catch (err) {
      console.error('Erro na importação:', err);
