                      <div key={course.id} className={`p-2 rounded-xl border text-center ${t.status === 'NOT_TRAINED' ? 'bg-gray-50 border-gray-100 opacity-40' : 'bg-white border-gray-200 shadow-sm'}`}>
                        <p className="text-[8px] font-black text-gray-400 mb-1">{course.id}</p>
                        <p className={`text-[9px] font-bold ${t.status === 'NOT_TRAINED' ? 'text-gray-300' : 'text-gray-700'}`}>
                          {t.completionDate ? new Date(t.completionDate).toLocaleDateString('pt-BR', {year: '2y'}) : '---'}
                        </p>
                        <div className={`mt-1 h-1 w-full rounded-full ${cfg.color}`}></div>
                      </div>
                    )
                  })}
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

