import React, { useState, useMemo } from 'react';
import { Employee, TrainingStatus, TrainingRecord } from '../types';
import { NR_COURSES, STATUS_CONFIG } from '../constants';
import { getDaysRemaining } from '../utils/calculations';

interface ReportsProps {
  employees: Employee[];
}

const Reports: React.FC<ReportsProps> = ({ employees }) => {
  const [filters, setFilters] = useState({
    department: '',
    status: '' as TrainingStatus | '',
    course: '',
    search: '',
    period: 'all' as 'all' | '15' | '30' | '60' | 'expired',
  });

  const departments = useMemo(() => Array.from(new Set(employees.map(e => e.department))), [employees]);

  const reportData = useMemo(() => {
    let result: any[] = [];

    employees.forEach(emp => {
      Object.entries(emp.trainings).forEach(([cid, record]) => {
        const t = record as TrainingRecord;
        const days = getDaysRemaining(t.expiryDate);

        const matchesSearch = emp.name.toLowerCase().includes(filters.search.toLowerCase()) || 
                             emp.registration.includes(filters.search);
        const matchesDept = !filters.department || emp.department === filters.department;
        const matchesStatus = !filters.status || t.status === filters.status;
        const matchesCourse = !filters.course || cid === filters.course;

        // Filtro de período específico
        let matchesPeriod = true;
        if (filters.period === '15') matchesPeriod = days !== null && days <= 15 && days >= 0;
        else if (filters.period === '30') matchesPeriod = days !== null && days <= 30 && days >= 0;
        else if (filters.period === '60') matchesPeriod = days !== null && days <= 60 && days >= 0;
        else if (filters.period === 'expired') matchesPeriod = t.status === 'EXPIRED';

        if (matchesSearch && matchesDept && matchesStatus && matchesCourse && matchesPeriod) {
          result.push({ employee: emp, courseId: cid, record: t, days });
        }
      });
    });

    return result;
  }, [employees, filters]);

  return (
    <div className="space-y-6 pb-20">
      <div className="flex justify-between items-center no-print">
        <h2 className="text-3xl font-black text-gray-800 tracking-tighter">Central de <span className="text-green-600">Relatórios</span></h2>
        <button 
          onClick={() => window.print()}
          className="bg-[#064E3B] text-green-400 px-8 py-3 rounded-2xl hover:bg-green-900 transition-all font-black text-xs uppercase tracking-widest shadow-xl shadow-green-900/20"
        >
          🖨️ Imprimir / Exportar PDF
        </button>
      </div>

      <div className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-gray-100 no-print space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-5 gap-4">
          <div className="md:col-span-2">
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">Busca Colaborador</label>
            <input 
              type="text" 
              className="w-full bg-gray-50 border-2 border-gray-100 rounded-xl p-3 outline-none focus:border-green-500 text-sm font-bold"
              placeholder="Nome ou matrícula..."
              value={filters.search}
              onChange={(e) => setFilters(f => ({ ...f, search: e.target.value }))}
            />
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">Filtrar por Vencimento</label>
            <select 
              className="w-full bg-gray-50 border-2 border-gray-100 rounded-xl p-3 outline-none focus:border-green-500 text-sm font-bold"
              value={filters.period}
              onChange={(e) => setFilters(f => ({ ...f, period: e.target.value as any }))}
            >
              <option value="all">Todos os períodos</option>
              <option value="15">Vence em 15 dias</option>
              <option value="30">Vence em 30 dias</option>
              <option value="60">Vence em 60 dias</option>
              <option value="expired">Já Vencidos</option>
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">Setor</label>
            <select 
              className="w-full bg-gray-50 border-2 border-gray-100 rounded-xl p-3 outline-none focus:border-green-500 text-sm font-bold"
              value={filters.department}
              onChange={(e) => setFilters(f => ({ ...f, department: e.target.value }))}
            >
              <option value="">Todos os Setores</option>
              {departments.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-[10px] font-black text-gray-400 uppercase mb-2 tracking-widest">Curso (NR)</label>
            <select 
              className="w-full bg-gray-50 border-2 border-gray-100 rounded-xl p-3 outline-none focus:border-green-500 text-sm font-bold"
              value={filters.course}
              onChange={(e) => setFilters(f => ({ ...f, course: e.target.value }))}
            >
              <option value="">Todos os Cursos</option>
              {NR_COURSES.map(c => <option key={c.id} value={c.id}>{c.id}</option>)}
            </select>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-[2.5rem] shadow-sm overflow-hidden border border-gray-100">
        <div className="hidden print-only p-12 text-center border-b">
          <div className="flex justify-center mb-4">🛡️</div>
          <h1 className="text-3xl font-black text-gray-900">Relatório de Treinamentos de SST</h1>
          <p className="text-gray-500 uppercase text-xs font-bold tracking-widest mt-2">Documento Gerado em: {new Date().toLocaleDateString('pt-BR')}</p>
        </div>

        <table className="w-full text-left text-xs">
          <thead className="bg-gray-50 text-gray-400 font-black uppercase text-[10px] tracking-[0.2em] border-b">
            <tr>
              <th className="px-6 py-5">Colaborador</th>
              <th className="px-6 py-5">Setor</th>
              <th className="px-6 py-5">Treinamento</th>
              <th className="px-6 py-5">Realização</th>
              <th className="px-6 py-5">Vencimento</th>
              <th className="px-6 py-5">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {reportData.map((item, idx) => (
              <tr key={idx} className="hover:bg-gray-50/50 transition-colors">
                <td className="px-6 py-4">
                  <p className="font-black text-gray-800">{item.employee.name}</p>
                  <p className="text-[10px] text-gray-400 uppercase font-bold">{item.employee.registration}</p>
                </td>
                <td className="px-6 py-4 font-bold text-gray-500 uppercase">{item.employee.department}</td>
                <td className="px-6 py-4 font-black text-green-700">{item.courseId}</td>
                <td className="px-6 py-4 font-bold text-gray-600">{item.record.completionDate || '---'}</td>
                <td className="px-6 py-4">
                  <p className="font-bold text-gray-800">{item.record.expiryDate || '---'}</p>
                  {item.days !== null && (
                    <p className={`text-[9px] font-black uppercase ${item.days < 0 ? 'text-red-500' : 'text-amber-500'}`}>
                      {item.days < 0 ? 'Vencido' : `Vence em ${item.days} dias`}
                    </p>
                  )}
                </td>
                <td className="px-6 py-4">
                  <span className={`px-3 py-1.5 rounded-full text-[9px] font-black uppercase ${STATUS_CONFIG[item.record.status].bg} ${STATUS_CONFIG[item.record.status].text}`}>
                    {STATUS_CONFIG[item.record.status].label}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {reportData.length === 0 && (
          <div className="p-32 text-center">
            <span className="text-4xl block mb-4 opacity-20">🔎</span>
            <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest">Nenhum registro encontrado com estes filtros.</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default Reports;

