                onChange={(e) => setSearchTerm(e.target.value)}
              />
              <span className="absolute left-3 top-2.5 text-gray-400">🔍</span>
            </div>
          </div>
        </div>
        <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest hidden md:block">
          Exibindo {filtered.length} registros
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filtered.map(emp => (
          <div key={emp.id} className="bg-white rounded-[2rem] border border-gray-100 overflow-hidden hover:border-green-200 hover:shadow-lg transition-all group shadow-sm">
            <div className="p-5 flex flex-col md:flex-row md:items-center justify-between gap-4 bg-gray-50/30 group-hover:bg-white cursor-pointer transition-colors">
              <div className="flex items-center gap-4">
                <div className="w-12 h-12 bg-[#064E3B] text-green-400 rounded-2xl flex items-center justify-center font-black text-lg shadow-inner">
                  {emp.name.charAt(0)}
                </div>
                <div>
                  <h3 className="text-base font-black text-gray-800 leading-tight">{emp.name}</h3>
                  <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight mt-0.5">
                    MAT: {emp.registration} • {emp.role} • <span className="text-green-600 font-black">{emp.department}</span>
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap gap-1.5 justify-end">
                {NR_COURSES.map(course => {
                  const t = emp.trainings[course.id];
                  if (!t || t.status === 'NOT_TRAINED') return null;
                  const cfg = STATUS_CONFIG[t.status];
                  return (
                    <div key={course.id} className={`px-2.5 py-1 rounded-lg text-[9px] font-black border flex items-center gap-2 ${cfg.bg} ${cfg.text} border-black/5 shadow-sm`}>
                      <span className={`w-1.5 h-1.5 rounded-full ${cfg.color} animate-pulse`}></span>
                      {course.id}
                    </div>
                  );
                })}
              </div>
            </div>

            <div className="px-5 pb-5 hidden group-hover:block animate-fadeIn">
               <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 xl:grid-cols-5 gap-4 pt-5 border-t border-gray-100">
                  {NR_COURSES.map(course => {
                    const t = emp.trainings[course.id];
                    const cfg = STATUS_CONFIG[t?.status || 'NOT_TRAINED'];
                    const days = getDaysRemaining(t?.expiryDate);

                    return (
                      <div key={course.id} className={`p-4 rounded-3xl border flex flex-col justify-between transition-all ${!t || t.status === 'NOT_TRAINED' ? 'bg-gray-50/50 border-gray-100 opacity-40' : 'bg-white border-gray-100 shadow-sm relative overflow-hidden active:scale-95'}`}>
                        {t && t.status !== 'NOT_TRAINED' && (
                          <div className={`absolute top-0 right-0 h-1.5 w-full ${cfg.color}`}></div>
                        )}
                        <div className="flex justify-between items-start mb-3">
                           <p className="text-xs font-black text-gray-900">{course.id}</p>
                           <span className={`px-2 py-0.5 rounded-lg text-[8px] font-black uppercase ${cfg.bg} ${cfg.text}`}>
                             {STATUS_CONFIG[t?.status || 'NOT_TRAINED'].label}
                           </span>
                        </div>

                        <div className="space-y-1.5">
                          <div className="flex justify-between text-[10px]">
                            <span className="text-gray-400 font-bold">INÍCIO:</span>
                            <span className="text-gray-800 font-black">{t?.completionDate ? new Date(t.completionDate).toLocaleDateString('pt-BR') : '--/--/--'}</span>
                          </div>
                          <div className="flex justify-between text-[10px]">
                            <span className="text-gray-400 font-bold">EXPIRA:</span>
                            <span className="text-gray-800 font-black">{t?.expiryDate ? new Date(t.expiryDate).toLocaleDateString('pt-BR') : (t?.completionDate && !course.validityYears ? 'VITALÍCIO' : '--/--/--')}</span>
                          </div>
                          {days !== null && t?.status !== 'NOT_TRAINED' && (
                            <div className={`mt-3 p-2 rounded-xl text-center ${days < 0 ? 'bg-red-100/50' : days <= 60 ? 'bg-amber-100/50' : 'bg-green-100/50'}`}>
                              <p className={`text-[10px] font-black uppercase tracking-tighter ${days < 0 ? 'text-red-700' : days <= 60 ? 'text-amber-700' : 'text-green-700'}`}>
                                {days < 0 ? `Vencido há ${Math.abs(days)} dias` : `${days} dias p/ vencer`}
                              </p>
                            </div>
                          )}
                        </div>
                      </div>
                    )
                  })}
               </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default EmployeeView;

import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, PieChart, Pie, Legend } from 'recharts';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG } from '../constants';
import { getDaysRemaining } from '../utils/calculations';

interface DashboardProps {
  employees: Employee[];
}

const Dashboard: React.FC<DashboardProps> = ({ employees }) => {
  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0, none: 0 };
    const deptStats: Record<string, { total: number, valid: number, expiring: number, expired: number }> = {};
    const alert15: any[] = [];
    const alert30: any[] = [];
    const alert60: any[] = [];

    employees.forEach(emp => {
      if (!deptStats[emp.department]) {
        deptStats[emp.department] = { total: 0, valid: 0, expiring: 0, expired: 0 };
      }
      deptStats[emp.department].total++;

      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.status === 'VALID') { s.trained++; deptStats[emp.department].valid++; }
        else if (record.status === 'EXPIRING') { 
          s.expiring++; 
          deptStats[emp.department].expiring++;
          const alertObj = { emp, cid, days, expiryDate: record.expiryDate };
          if (days !== null && days <= 15) alert15.push(alertObj);
          else if (days !== null && days <= 30) alert30.push(alertObj);
          else alert60.push(alertObj);
        }
        else if (record.status === 'EXPIRED') { s.expired++; deptStats[emp.department].expired++; }
        else s.none++;
      });
    });

    return { s, deptStats, alerts: { a15: alert15, a30: alert30, a60: alert60 } };
  }, [employees]);

  const chartData = Object.entries(stats.deptStats).map(([name, data]: [string, any]) => ({
    name,
    Válidos: data.valid,
    Vencendo: data.expiring,
    Vencidos: data.expired,
    Total: data.total
  }));

  const pieData = [
    { name: 'Válidos', value: stats.s.trained, color: '#10B981' },
    { name: 'Vencendo', value: stats.s.expiring, color: '#F59E0B' },
    { name: 'Vencidos', value: stats.s.expired, color: '#EF4444' },
    { name: 'Inexistentes', value: stats.s.none, color: '#E5E7EB' },
  ];

  return (
    <div className="space-y-10 pb-20 animate-fadeIn">
      <header className="flex justify-between items-center">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tighter">Performance de <span className="text-green-600">SST</span></h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Monitoramento em Tempo Real de Treinamentos</p>
        </div>
      </header>

      {/* Indicadores Premium */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cursos Válidos', val: stats.s.trained, color: 'text-green-600', bg: 'bg-green-50', icon: '🛡️' },
          { label: 'Em Reciclagem', val: stats.s.expiring, color: 'text-amber-600', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Cursos Vencidos', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Total Funcionários', val: employees.length, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100">
            <div className="flex justify-between items-start">
              <span className={`text-2xl p-3 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-4xl font-black ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Gráfico de Headcount por Setor - NOVO */}
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-black text-gray-800 mb-2">Funcionários por Setor</h3>
          <p className="text-[10px] font-bold text-gray-400 uppercase mb-8 tracking-widest">Total de Pessoas por Departamento</p>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical">
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 10, fontWeight: 700}} width={80} />
                <Tooltip cursor={{fill: '#f8fafc'}} />
                <Bar dataKey="Total" fill="#064E3B" radius={[0, 10, 10, 0]} barSize={15} />
              </BarChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 space-y-2 max-h-40 overflow-y-auto pr-2 custom-scrollbar">
            {chartData.map(d => (
              <div key={d.name} className="flex justify-between items-center bg-gray-50 p-2 rounded-xl">
                <span className="text-[10px] font-black text-gray-500 uppercase">{d.name}</span>
                <span className="text-xs font-black text-[#064E3B]">{d.Total} func.</span>
              </div>
            ))}
          </div>
        </div>

        {/* Gráfico de Conformidade por Setor */}
        <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] shadow-sm border border-gray-100">
          <h3 className="text-xl font-black text-gray-800 mb-8">Conformidade de Treinamento</h3>
          <div className="h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical" margin={{ left: 20 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 11, fontWeight: 700}} width={80} />
                <Tooltip cursor={{fill: '#f8fafc'}} contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)' }} />
                <Legend verticalAlign="top" height={36}/>
                <Bar dataKey="Válidos" stackId="a" fill="#10B981" barSize={20} />
                <Bar dataKey="Vencendo" stackId="a" fill="#F59E0B" />
                <Bar dataKey="Vencidos" stackId="a" fill="#EF4444" radius={[0, 10, 10, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* Sistema de Alertas de Treinamento */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {[
          { title: 'Crítico (15 dias)', data: stats.alerts.a15, color: 'border-red-500', bg: 'bg-red-500', text: 'text-red-700' },
          { title: 'Urgente (30 dias)', data: stats.alerts.a30, color: 'border-amber-500', bg: 'bg-amber-500', text: 'text-amber-700' },
          { title: 'Alerta (60 dias)', data: stats.alerts.a60, color: 'border-blue-500', bg: 'bg-blue-500', text: 'text-blue-700' },
        ].map((alert, idx) => (
          <div key={idx} className={`bg-white rounded-[2rem] border-l-8 ${alert.color} shadow-sm overflow-hidden`}>
            <div className={`p-4 ${alert.bg} text-white font-black text-xs uppercase tracking-widest flex justify-between`}>
               {alert.title}
               <span className="bg-white/20 px-2 rounded-lg">{alert.data.length}</span>
            </div>
            <div className="p-4 space-y-3 max-h-64 overflow-y-auto">
              {alert.data.length === 0 ? (
                <p className="text-center text-gray-300 text-xs py-4 italic">Nenhum registro</p>
