                    </div>
                    <div className="text-right">
                      <p className={`text-[11px] font-black ${alert.text}`}>{item.days} dias</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

