}

const Reports: React.FC<ReportsProps> = ({ employees }) => {
  const [filters, setFilters] = useState({
    department: '',
    status: '' as TrainingStatus | '',
    course: '',
    search: '',
    period: 'all' as 'all' | '15' | '30' | '60' | 'expired',
  });

