import { Employee } from '../types';

const STORAGE_KEY = 'sst_management_data';

/**
 * Este serviço simula chamadas a um banco de dados.
 * Para tornar online, você substituirá o conteúdo destas funções
 * por chamadas ao SDK do Supabase ou Firebase.
 */
export const StorageService = {
  // Busca todos os funcionários
  async getEmployees(): Promise<Employee[]> {
    // Simula latência de rede
    await new Promise(resolve => setTimeout(resolve, 500));
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  },

  // Salva ou atualiza a lista completa
  async saveEmployees(employees: Employee[]): Promise<void> {
    await new Promise(resolve => setTimeout(resolve, 300));
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
  },

  // Adiciona novos funcionários (usado na importação)
  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const updated = [...current, ...newEmployees];
    await this.saveEmployees(updated);
    return updated;
  },

  // Limpa o banco de dados (opcional)
  async clearAll(): Promise<void> {
    localStorage.removeItem(STORAGE_KEY);
  }
};

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import { Employee } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  // Carregamento inicial do "Banco de Dados"
  useEffect(() => {
    const loadData = async () => {
      setIsLoading(true);
      try {
        const data = await StorageService.getEmployees();
        setEmployees(data);
      } catch (error) {
        console.error("Erro ao carregar dados:", error);
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, []);

  const handleImport = async (data: Employee[]) => {
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4 animate-fadeIn">
          <div className="w-16 h-16 border-4 border-green-200 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Sincronizando Banco de Dados...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return <ImportData onImport={handleImport} />;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

