import { Employee } from '../types';
import { formatEmployeeData } from '../utils/calculations';

const STORAGE_KEY = 'sst_management_data';
const SHEETS_URL_KEY = 'sst_sheets_api_url';

export const StorageService = {
  // Salva a URL da API do Google Sheets
  saveSheetsUrl(url: string) {
    localStorage.setItem(SHEETS_URL_KEY, url);
  },

  getSheetsUrl(): string | null {
    return localStorage.getItem(SHEETS_URL_KEY);
  },

  // Busca dados (Prioriza Google Sheets se configurado, senão LocalStorage)
  async getEmployees(): Promise<Employee[]> {
    const sheetsUrl = this.getSheetsUrl();

    if (sheetsUrl) {
      try {
        const response = await fetch(sheetsUrl);
        if (!response.ok) throw new Error('Falha na resposta da rede');
        const rawData = await response.json();
        return formatEmployeeData(rawData);
      } catch (error) {
        console.error("Erro ao buscar dados do Google Sheets:", error);
        // Fallback para dados locais se a rede falhar
      }
    }

    const localData = localStorage.getItem(STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async saveEmployees(employees: Employee[]): Promise<void> {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
    // Nota: Para salvar de volta no Sheets, seria necessário implementar o doPost no Apps Script
  },

  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const updated = [...current, ...newEmployees];
    await this.saveEmployees(updated);
    return updated;
  }
};

