import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import { Employee } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleImport = async (data: Employee[]) => {
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4 animate-fadeIn">
          <div className="w-16 h-16 border-4 border-green-200 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Sincronizando com a Nuvem...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return <ImportData onImport={handleImport} />;
      case 'config': return <ConfigView onUpdate={loadData} />;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { Employee } from '../types';
import { formatEmployeeData } from '../utils/calculations';

const STORAGE_KEY = 'sst_management_data';
const SHEETS_URL_KEY = 'sst_sheets_api_url';

export const StorageService = {
  saveSheetsUrl(url: string) {
    // Garante que a URL termine com /exec para funcionar corretamente
    const cleanUrl = url.trim().replace(/\/$/, '');
    const finalUrl = cleanUrl.endsWith('/exec') ? cleanUrl : `${cleanUrl}/exec`;
    localStorage.setItem(SHEETS_URL_KEY, finalUrl);
  },

  getSheetsUrl(): string | null {
    return localStorage.getItem(SHEETS_URL_KEY);
  },

  async getEmployees(): Promise<Employee[]> {
    const sheetsUrl = this.getSheetsUrl();

    if (sheetsUrl) {
      try {
        // cache: 'no-store' garante que buscaremos dados novos da planilha toda vez
        const response = await fetch(sheetsUrl, { cache: 'no-store' });
        if (!response.ok) throw new Error('Erro na conexão com Google');
        const rawData = await response.json();
        return formatEmployeeData(rawData);
      } catch (error) {
        console.error("Erro ao sincronizar nuvem:", error);
      }
    }

    const localData = localStorage.getItem(STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async saveEmployees(employees: Employee[]): Promise<void> {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
  },

  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const updated = [...current, ...newEmployees];
    await this.saveEmployees(updated);
    return updated;
  }
};

import React, { useMemo, useState } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, Legend } from 'recharts';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG, getDeptColor } from '../constants';
import { getDaysRemaining } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface DashboardProps {
  employees: Employee[];
  onRefresh?: () => void;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[200px]">
        <p className="font-black text-gray-800 mb-2 border-b pb-1 text-sm">{label}</p>
        <div className="space-y-1.5">
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex justify-between items-center gap-4 text-[11px]">
              <div className="flex items-center gap-2">
                <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: entry.color }}></div>
                <span className="font-bold text-gray-500 uppercase">{entry.name}</span>
              </div>
              <span className="font-black text-gray-800">{entry.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees, onRefresh }) => {
  const [isSyncing, setIsSyncing] = useState(false);
  const isCloud = !!StorageService.getSheetsUrl();

  const handleManualRefresh = async () => {
    if (!onRefresh) return;
    setIsSyncing(true);
    await onRefresh();
    setTimeout(() => setIsSyncing(false), 1000);
  };

  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0, none: 0 };
    const deptStats: Record<string, { total: number, valid: number, expiring: number, expired: number }> = {};
    const alert15: any[] = [];
    const alert30: any[] = [];
    const alert60: any[] = [];

    employees.forEach(emp => {
      const dept = emp.department || 'Não Definido';
      if (!deptStats[dept]) {
        deptStats[dept] = { total: 0, valid: 0, expiring: 0, expired: 0 };
      }
      deptStats[dept].total++;

      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.status === 'VALID') { s.trained++; deptStats[dept].valid++; }
        else if (record.status === 'EXPIRING') { 
          s.expiring++; 
          deptStats[dept].expiring++;
          const alertObj = { emp, cid, days, expiryDate: record.expiryDate };
          if (days !== null && days <= 15) alert15.push(alertObj);
          else if (days !== null && days <= 30) alert30.push(alertObj);
          else alert60.push(alertObj);
        }
        else if (record.status === 'EXPIRED') { s.expired++; deptStats[dept].expired++; }
        else s.none++;
      });
    });

    return { s, deptStats, alerts: { a15: alert15, a30: alert30, a60: alert60 } };
  }, [employees]);

  const chartData = Object.entries(stats.deptStats).map(([name, data]: [string, any]) => ({
    name,
    Válidos: data.valid,
    Vencendo: data.expiring,
    Vencidos: data.expired,
    Total: data.total,
    fill: getDeptColor(name)
  }));

  return (
    <div className="space-y-10 pb-20 animate-fadeIn">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tighter">Performance de <span className="text-green-600">SST</span></h2>
