        </div>

        {onRefresh && (
          <button 
            onClick={handleManualRefresh}
            disabled={isSyncing}
            className={`flex items-center gap-3 px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] transition-all shadow-lg ${
              isCloud 
                ? 'bg-green-100 text-green-700 hover:bg-green-200' 
                : 'bg-gray-100 text-gray-500 cursor-not-allowed'
            }`}
          >
            <span className={isSyncing ? 'animate-spin' : ''}>{isSyncing ? '🔄' : '☁️'}</span>
            {isSyncing ? 'Sincronizando...' : 'Sincronizar Planilha'}
          </button>
        )}
      </header>

      {/* Indicadores Principais */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cursos Válidos', val: stats.s.trained, color: 'text-green-600', bg: 'bg-green-50', icon: '🛡️' },
          { label: 'Em Reciclagem', val: stats.s.expiring, color: 'text-amber-600', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Cursos Vencidos', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Total Funcionários', val: employees.length, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 transition-transform hover:scale-[1.02]">
            <div className="flex justify-between items-start">
              <span className={`text-2xl p-3 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-4xl font-black ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-4 text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
