import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import { Employee } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleImport = async (data: Employee[]) => {
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados. Tente novamente.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4 animate-fadeIn">
          <div className="w-16 h-16 border-4 border-green-200 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Sincronizando com a Nuvem...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} onRefresh={loadData} />;
      case 'employees': return <EmployeeView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return <ImportData onImport={handleImport} />;
      case 'config': return <ConfigView onUpdate={loadData} />;
      default: return <Dashboard employees={employees} onRefresh={loadData} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;

import { Employee } from '../types';
import { formatEmployeeData } from '../utils/calculations';

const STORAGE_KEY = 'sst_management_data';
const SHEETS_URL_KEY = 'sst_sheets_api_url';

export const StorageService = {
  saveSheetsUrl(url: string) {
    let cleanUrl = url.trim();
    if (!cleanUrl) {
      localStorage.removeItem(SHEETS_URL_KEY);
      return;
    }
    // Garante que a URL termine com /exec
    cleanUrl = cleanUrl.replace(/\/$/, '');
    if (!cleanUrl.endsWith('/exec')) {
      cleanUrl += '/exec';
    }
    localStorage.setItem(SHEETS_URL_KEY, cleanUrl);
  },

  getSheetsUrl(): string | null {
    return localStorage.getItem(SHEETS_URL_KEY);
  },

  async getEmployees(): Promise<Employee[]> {
    const sheetsUrl = this.getSheetsUrl();

    if (sheetsUrl) {
      try {
        console.log("Iniciando sincronização com:", sheetsUrl);
        const response = await fetch(sheetsUrl, { 
          method: 'GET',
          mode: 'cors',
          cache: 'no-store'
        });

        if (!response.ok) {
          throw new Error(`HTTP Error: ${response.status}`);
        }

        const rawData = await response.json();

        if (!Array.isArray(rawData)) {
          throw new Error("A planilha não retornou uma lista válida de dados.");
        }

        console.log("Dados brutos recebidos:", rawData.length, "linhas");
        const formatted = formatEmployeeData(rawData);

        // Salva uma cópia local para cache offline
        this.saveEmployees(formatted);
        return formatted;
      } catch (error) {
        console.error("Erro crítico na sincronização Cloud:", error);
        // Em caso de erro, tenta carregar o que estiver no cache local
      }
    }

    const localData = localStorage.getItem(STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async saveEmployees(employees: Employee[]): Promise<void> {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
  },

  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const updated = [...current, ...newEmployees];
    await this.saveEmployees(updated);
    return updated;
  }
};

