const STORAGE_KEY = 'sst_management_data';
const SHEETS_URL_KEY = 'sst_sheets_url';

export const StorageService = {
  // Retorna a URL salva do Google Sheets para sincronização
  getSheetsUrl(): string | null {
    return localStorage.getItem(SHEETS_URL_KEY);
  },

  // Salva a URL do Google Sheets no armazenamento local
  saveSheetsUrl(url: string): void {
    localStorage.setItem(SHEETS_URL_KEY, url);
  },

  async getEmployees(): Promise<Employee[]> {
    const localData = localStorage.getItem(STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async saveEmployees(employees: Employee[]): Promise<void> {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
  },

  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const merged = [...current];

    newEmployees.forEach(newEmp => {
      const index = merged.findIndex(e => 
        (e.registration !== '-' && e.registration === newEmp.registration) || 
        (e.id === newEmp.id)
      );

      if (index !== -1) {
        merged[index] = { ...merged[index], ...newEmp };
      } else {
        merged.push(newEmp);
      }
    });

    await this.saveEmployees(merged);
    return merged;
  },

  async updateEmployee(updatedEmp: Employee): Promise<Employee[]> {
    const employees = await this.getEmployees();
    const index = employees.findIndex(e => e.id === updatedEmp.id);
    if (index !== -1) {
      employees[index] = updatedEmp;
    } else {
      employees.push(updatedEmp);
    }
    await this.saveEmployees(employees);
    return employees;
  },

  async deleteEmployee(id: string): Promise<Employee[]> {
    const employees = await this.getEmployees();
    const filtered = employees.filter(e => e.id !== id);
    await this.saveEmployees(filtered);
    return filtered;
  },

  downloadBackup() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (!data) return;
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backup_sst_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  }
};

import React, { useState } from 'react';
import { StorageService } from '../services/storage';
import { formatEmployeeData } from '../utils/calculations';

const ConfigView: React.FC<{ onUpdate: () => void }> = ({ onUpdate }) => {
  const [url, setUrl] = useState(StorageService.getSheetsUrl() || '');
  const [status, setStatus] = useState<'idle' | 'testing' | 'success' | 'error'>('idle');
  const [errorMessage, setErrorMessage] = useState('');
  const [testResult, setTestResult] = useState<any>(null);

  const scriptCode = `function doGet() {
  try {
    const ss = SpreadsheetApp.getActiveSpreadsheet();
    const sheet = ss.getSheets()[0];
    const data = sheet.getDataRange().getValues();
    const headers = data[0];
    const rows = data.slice(1);

    const json = rows.map(row => {
      const obj = {};
      headers.forEach((header, i) => {
        obj[header] = row[i];
      });
      return obj;
    });

    return ContentService.createTextOutput(JSON.stringify(json))
      .setMimeType(ContentService.MimeType.JSON);
  } catch (e) {
    return ContentService.createTextOutput(JSON.stringify({ error: e.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}`;

  const copyToClipboard = () => {
    navigator.clipboard.writeText(scriptCode);
    alert('Código copiado! Cole no seu Editor do Google Apps Script.');
  };

  const validateAndTest = async () => {
    if (!url.includes('script.google.com')) {
      setStatus('error');
      setErrorMessage('A URL fornecida não é um link válido do Google Scripts.');
      return;
    }

    setStatus('testing');
    setErrorMessage('');
    setTestResult(null);

    let testUrl = url.trim();
    if (!testUrl.endsWith('/exec')) {
       testUrl = testUrl.replace(/\/$/, '') + '/exec';
    }

    try {
      const response = await fetch(testUrl, { cache: 'no-store' });
      const data = await response.json();

      if (data.error) {
        throw new Error(`Erro no Script: ${data.error}`);
      }

      if (Array.isArray(data)) {
        // Converte os dados brutos da planilha para o formato do sistema e persiste localmente
        const employees = formatEmployeeData(data);
        await StorageService.saveEmployees(employees);

        setTestResult({
          count: employees.length,
          cols: data.length > 0 ? Object.keys(data[0]).slice(0, 5).join(', ') + '...' : 'Nenhuma'
        });
        setStatus('success');
        StorageService.saveSheetsUrl(url);
        onUpdate();
      } else {
        throw new Error("O script não retornou uma lista de funcionários.");
      }
    } catch (err: any) {
      console.error(err);
      setStatus('error');
      setErrorMessage(err.message || 'Falha ao acessar o Script. Verifique se publicou como "Qualquer pessoa".');
    }
  };

  return (
    <div className="max-w-5xl mx-auto animate-fadeIn space-y-8 pb-20">
      <div className="bg-white p-10 rounded-[3rem] shadow-sm border border-gray-100">
        <header className="mb-10 text-center">
