import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import { Employee } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleImport = async (data: Employee[]) => {
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-green-100 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Carregando Banco SST...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} onUpdate={loadData} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return (
        <div className="space-y-10">
           <ImportData onImport={handleImport} />
           <div className="max-w-6xl mx-auto bg-white p-8 rounded-[2.5rem] border border-gray-100 flex items-center justify-between shadow-sm">
             <div>
                <h4 className="font-black text-gray-800">Cópia de Segurança (Backup)</h4>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Baixe todos os dados para o seu computador</p>
             </div>
             <button 
                onClick={() => StorageService.downloadBackup()}
                className="bg-blue-50 text-blue-600 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-100 transition-all"
             >
                Baixar Arquivo .JSON 💾
             </button>
           </div>
        </div>
      );
      case 'config': return <ConfigView onUpdate={loadData} />;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout activeTab={activeTab} setActiveTab={setActiveTab}>
      {renderContent()}
    </Layout>
  );
};

export default App;
